let isChatInputFocused = false;

// if  nM.nMw - last char one of mine - render that skin - NwW = 6,7;

// 6 - devil
// 7 - hypr
// thats it - func that takes nick and original number and returns number of a skin if change

function applySkin(nick, originalNumber) {
  // if one of mine change number
  const lastChar = nick.slice(-1);

  switch (lastChar) {
    case "​":
      return 6;
    case "⁤":
      return 7;
    case "⠀":
      return 8;
    default:
      return originalNumber;
  }
}

function putOnSkin(rawNick) {
  const skin = localStorage.getItem("ModSkin");

  const nick = rawNick.substring(0, 15);

  switch (skin) {
    case "Default":
      return nick;
    case "Athlete":
      return nick + "⠀";
    case "Devil":
      return nick + "​";
    case "Fury":
      return nick + "⁤";
    default:
      return nick;
  }
}

