const howToPlayTextDiv = document.getElementById("howtoplayText");

// Retrieve the ModSkin value from local storage
let modSkin = localStorage.getItem("ModSkin");

// If the ModSkin value doesn't exist, set it to Default
if (!modSkin) {
  modSkin = "Default";
  localStorage.setItem("ModSkin", modSkin); // Save the default value to local storage
}

howToPlayTextDiv.textContent = `Selected: ${modSkin}`;

// Get the container element
const container = document.getElementById("howtoplay");

// Function to create a button
function createButton(text, top, left) {
  // Create a new button element
  const button = document.createElement("button");

  // Set the button text
  button.textContent = text;

  // Set the style for the button
  button.style.position = "absolute";
  button.style.top = `${top}`;
  button.style.left = `${left}`;
  button.style.backgroundColor = "black";
  button.style.color = "white";
  button.style.border = "none";
  button.style.padding = "10px 20px";
  button.style.fontSize = "16px";
  button.style.cursor = "pointer";
  button.style.width = "90px"; // Set the width
  button.style.height = "35px"; // Set the height

  button.style.fontFamily = "Viga";
  button.style.borderRadius = "8px 8px 8px 8px";

  // Add an event listener to set the skin when the button is clicked
  button.addEventListener("click", function () {
    // Set the skin in local storage
    localStorage.setItem("ModSkin", text);

    // Update the text of the #howtoplayText div
    howToPlayTextDiv.textContent = `Selected: ${text}`;
  });

  // Add a hover effect to the button
  button.onmouseover = function () {
    this.style.backgroundColor = "#333";
  };

  button.onmouseout = function () {
    this.style.backgroundColor = "black";
  };

  // Append the button to the container
  container.appendChild(button);
}

// Create four buttons with different positions
createButton("Default", "45%", "15%");
createButton("Athlete", "45%", "55%");
createButton("Devil", "73%", "15%");
createButton("Fury", "73%", "55%");

