async function sendWebhookMessage(payload) {
  try {
    const response = await fetch(
      `${purpleOasisUrl}devastmod-chat-discord-webhook`,
      {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(payload),
      }
    );

    // if (response.ok) {
    //   console.log('Webhook sent successfully!');
    // } else {
    //   console.error('Failed to send webhook:', response.status, response.statusText);
    // }
  } catch (error) {
    // console.error('An error occurred:', error);
  }
}

// Create the chat container
const chatContainer = document.createElement("div");
chatContainer.style.position = "absolute";
chatContainer.style.top = "23%"; // 50 pixels from the top
chatContainer.style.left = "10px"; // 10 pixels from the left
chatContainer.style.width = "300px"; // Set the width to 200 pixels
chatContainer.style.height = "46%"; // 70% of the window height
chatContainer.style.background = "rgba(0, 0, 0, 0.5)"; // Black with 50% opacity
chatContainer.style.borderRadius = "8px"; // Add rounded corners
chatContainer.style.overflow = "hidden";
chatContainer.style.border = "2px solid black";

// Add the chat container to the body of the HTML document
document.body.appendChild(chatContainer);

// Create the chat toggle button
const chatToggleButton = document.createElement("div");
chatToggleButton.style.position = "absolute";
chatToggleButton.style.top = "165px";
chatToggleButton.style.left = "16px";
chatToggleButton.style.width = "25px";
chatToggleButton.style.height = "25px";
chatToggleButton.style.background = "rgba(0, 0, 0, 0.5)";
chatToggleButton.style.borderRadius = "50%";
chatToggleButton.style.cursor = "pointer";
chatToggleButton.style.zIndex = "1";

// Create a smaller black circle inside the chat toggle button
const chatToggleCircle = document.createElement("div");
chatToggleCircle.style.position = "absolute";
chatToggleCircle.style.top = "6px";
chatToggleCircle.style.left = "6px";
chatToggleCircle.style.width = "13px";
chatToggleCircle.style.height = "13px";
chatToggleCircle.style.background = "rgba(255, 255, 255, 0.5)";
chatToggleCircle.style.borderRadius = "50%";

const chatON = localStorage.getItem("ModChat");
if (!chatON) {
  chatContainer.style.display = "block";
  chatToggleCircle.style.display = "block";
  localStorage.setItem("ModChat", "1");
} else if (chatON == "1") {
  chatContainer.style.display = "block";
  chatToggleCircle.style.display = "block";
} else if (chatON == "0") {
  chatContainer.style.display = "none";
  chatToggleCircle.style.display = "none";
}

// Add the smaller black circle to the chat toggle button
chatToggleButton.appendChild(chatToggleCircle);

// Add the chat toggle button to the body of the HTML document
document.body.appendChild(chatToggleButton);

// Create the chat input box
const chatInput = document.createElement("input");
chatInput.type = "text";
chatInput.placeholder = "Enter text...";
chatInput.style.color = "white";

// Create a container for the input box to hold its height
const chatInputContainer = document.createElement("div");
chatInputContainer.appendChild(chatInput);

// Style the input container to remain at the bottom of the chat container
chatInputContainer.style.position = "absolute";
chatInputContainer.style.bottom = "0px";
chatInputContainer.style.width = "88%";
chatInputContainer.style.padding = "10px";

// Style the input box to fill its container
chatInput.style.width = "100%";
chatInput.style.height = "100%";
chatInput.style.padding = "10px";
chatInput.style.borderRadius = "8px 8px 8px 8px"; // Match the bottom corners of the parent
chatInput.style.borderStyle = "hidden";

chatInput.style.backgroundColor = "black";
chatInput.maxLength = 100;

// Add the input container to the chat container
chatContainer.appendChild(chatInputContainer);

// Create the chat messages area
const chatMessages = document.createElement("div");

// Style the chat messages area to expand to the full height of the chat container
chatMessages.style.position = "absolute";
chatMessages.style.top = "0px";
chatMessages.style.bottom = "45px"; // adjust this to match the height of the input box
chatMessages.style.width = "100%";
chatMessages.style.overflowY = "auto"; // enable scrolling when necessary

// Style the chat messages area with some basic styles

chatMessages.style.padding = "6px";
chatMessages.style.paddingLeft = "12px";

chatMessages.style.paddingRight = "12px";
// chatMessages.style.backgroundColor = "rgba(255, 255, 255, 0.1)";
// chatMessages.style.borderBottom = "1px solid rgba(255, 255, 255, 0.1)";
// chatMessages.style.borderRadius = "8px 8px 0px 0px";

// Add the chat messages area to the chat container
chatContainer.appendChild(chatMessages);

// Style the chat container to use the Viga font
chatContainer.style.fontFamily = "Viga";

// Style the chat input box to use the Viga font
chatInput.style.fontFamily = "Viga";

// Style the chat messages area to use the Viga font
chatMessages.style.fontFamily = "Viga";
chatMessages.style.color = "white";
chatMessages.style.fontSize = "13px";
chatMessages.style.overflowWrap = "break-word";
chatMessages.style.textShadow =
  "2px 2px black, -2px 2px black, -2px -2px black, 2px -2px black";

let last_user = "";

// Create a new message to add to the chat messages area
function addMessage(message) {
  const newMessage = document.createElement("div");
  newMessage.textContent = message;
  // newMessage.style.padding = "2px";
  // newMessage.style.borderBottom = "1px solid rgba(255, 255, 255, 0.1)";
  chatMessages.appendChild(newMessage);

  // scroll the messages area to the bottom when a new message is added
  chatMessages.scrollTop = chatMessages.scrollHeight;
}
function addUser(user) {
  if (last_user == user) return;
  const newMessage = document.createElement("div");
  newMessage.textContent = user;
  newMessage.style.paddingTop = "10px";
  newMessage.style.color = "#D3BB43";
  // newMessage.style.padding = "2px";
  // newMessage.style.borderBottom = "1px solid rgba(255, 255, 255, 0.1)";
  chatMessages.appendChild(newMessage);

  last_user = user;

  // scroll the messages area to the bottom when a new message is added
  chatMessages.scrollTop = chatMessages.scrollHeight;
}

async function subscribe_events() {
  const history = await window.channel.history();
  const lastMessages = history.items.reverse().slice(0, 50); // Trim to 50 last messages
  lastMessages.forEach((payload) => {
    processMessage(payload);
  });

  await window.channel.subscribe("message", (payload) => {
    processMessage(payload);
  });
}

async function processMessage(payload) {
  const server = payload.data.server.trim().substr(0, 12);
  const nick = payload.data.nick.trim().substr(0, 16);
  const message = payload.data.message.trim().substr(0, 100);
  // if (last_user == user) return;
  addUser(server + " | " + nick);
  addMessage(message);
}
subscribe_events();

// Function to toggle the chat visibility
function toggleChatVisibility() {
  if (chatContainer.style.display == "none") {
    chatContainer.style.display = "block";
    chatToggleCircle.style.display = "block";
    localStorage.setItem("ModChat", "1");
  } else {
    chatContainer.style.display = "none";
    chatToggleCircle.style.display = "none";
    localStorage.setItem("ModChat", "0");
  }
}

// Add an event listener to the chat toggle button to toggle the chat visibility
chatToggleButton.addEventListener("click", toggleChatVisibility);

// Add an event listener to the chat input box to listen for the Enter key
chatInput.addEventListener("keyup", async (event) => {
  // Check if the pressed key is the Enter key
  if (event.key === "Enter") {
    // Prevent the default behavior
    event.preventDefault();

    // Get the input value and trim it to remove any leading or trailing whitespace
    const inputValue = chatInput.value.trim();

    // Check if the input value is not empty
    if (inputValue !== "") {
      // Add the message to the chat messages area
      // addMessage(inputValue);
      let serverRaw;
      try {
        serverRaw = window.WebSocketClient.vnNWv.region.display_name;
      } catch {
        serverRaw = "Menu";
      }
      let nickRaw;
      try {
        nickRaw = window.SERVG.socket[window.SERVG.PLAYER.id].nMw; //"yamete";
      } catch {
        const lcStrNick = localStorage.getItem("nickname");
        nickRaw = lcStrNick ? lcStrNick : "Ghost";
      }
      // nMw is nick

      const server = serverRaw.trim().substr(0, 12);
      const nick = nickRaw.trim().substr(0, 16);
      const message = inputValue.trim().substr(0, 100);

      await window.sendMessage(server, nick, message);

      const payload = {
        username: `${server} | ${nick}`,
        message: message,
      };
      sendWebhookMessage(payload);

      // Clear the input box
      chatInput.value = "";

      isChatInputFocused = false;

      // Set a 1-second timeout before accepting the next message
      event.target.disabled = true;
      setTimeout(() => {
        event.target.disabled = false;
      }, 1000);
    }
  }
});

// Add event listeners to track focus and blur
chatInput.addEventListener("focus", () => {
  isChatInputFocused = true;
});

chatInput.addEventListener("blur", () => {
  isChatInputFocused = false;
});

